Patch Set 16:

You will need to rebase the patch. cfs_daemonize is gone so
osd_scrub.c needed to be updated. He is the difference I have been using in my testing.

diff --git a/lustre/osd-ldiskfs/osd_scrub.c b/lustre/osd-ldiskfs/osd_scrub.c
-index bf6a8b9..b32c418 100644
+index a6248e4..76347c8 100644
 --- a/lustre/osd-ldiskfs/osd_scrub.c
 +++ b/lustre/osd-ldiskfs/osd_scrub.c
-@@ -1028,7 +1028,7 @@ static int osd_scrub_main(void *args)
+@@ -1020,7 +1020,7 @@ static int osd_scrub_main(void *args)
+       int                   rc;
        ENTRY;

-       cfs_daemonize("OI_scrub");
 -      rc = lu_env_init(&env, LCT_DT_THREAD);
 +      rc = lu_env_init(&env, LCT_LOCAL);
        if (rc != 0) {
                CERROR("%.16s: OI scrub, fail to init env, rc = %d\n",
                       LDISKFS_SB(sb)->s_es->s_volume_name, rc);
